    KernelTripletMarginLossCustom op;
    op.Init(anchor, positive, negative, loss,
            tiling_data.totalTriplets, tiling_data.featureDim,
            tiling_data.tileDimF, tiling_data.margin, tiling_data.invTotalTriplets);
    op.Process();
}
